qry:select.qry:xquery:
			for $r in sql('
	SELECT 				
		PER.oi_personal
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG, 
		ORG03_EMPRESAS as EMP
	JOIN 
		PER.oi_personal INNER LEG.oi_personal,
		LEG.oi_empresa INNER EMP.oi_empresa				
	WHERE 1=1
		{%?(#SOURCE:@activos='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
		{%?(#SOURCE:@empresa!='') {% and LEG.oi_empresa = {#SOURCE:@empresa} %} {% %} %}
		{%?(#SOURCE:@nombre!='') {% and contain(ucase(PER.d_ape_y_nom), {upper_case(#SOURCE:@nombre)}) %} {% %} %}
		{%?(#SOURCE:@documento!='') {% and contain(PER.c_nro_documento, {#SOURCE:@documento}) %} {% %} %}
		{%?(#SOURCE:@sexo!='') {% and PER.c_sexo = {#SOURCE:@sexo} %} {% %} %}
		{%?(#SOURCE:@grupo_sanguineo!='') {% and PER.oi_grupo_sanguineo = {#SOURCE:@grupo_sanguineo} %} {% %} %}
		{%?(#SOURCE:@where!='') {% and {%=#SOURCE:@where %} %} {% %} %}
	GROUP BY
		PER.oi_personal
')/ROWS/ROW

			for $r in sql('
	SELECT
		PER.oi_personal
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG, 
		ORG03_EMPRESAS as EMP
	JOIN 
		PER.oi_personal INNER LEG.oi_personal,
		LEG.oi_empresa INNER EMP.oi_empresa
	WHERE 1=1 
		{%?(#SOURCE:@activos='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
		{%?(#SOURCE:@empresa!='') {% and LEG.oi_empresa = {#SOURCE:@empresa} %} {% %} %}
		{%?(#SOURCE:@leg_where!='') {% and ({%=#SOURCE:@leg_where %}) %} {% %} %}            
		{%?(#SOURCE:@indic_activo!='') {% and LEG.oi_indic_activo = {#SOURCE:@indic_activo} %} {% %} %}
		{%?(#SOURCE:@egresado='1') {% and isnotnull(LEG.f_egreso) %} {% %} %}
		{%?(#SOURCE:@egresado='0') {% and isnull(LEG.f_egreso) %} {% %} %}
		{%?(#SOURCE:@tipo_per!='') {% and LEG.oi_tipo_personal = {#SOURCE:@tipo_per} %} {% %} %}
		{%?(#SOURCE:@forma_pago!='') {% and LEG.oi_forma_pago = {#SOURCE:@forma_pago} %} {% %} %}
		{%?(#SOURCE:@fecha_desde!='') {% and LEG.f_ingreso >= {Datetime(#SOURCE:@fecha_desde)} %} {% %} %}
		{%?(#SOURCE:@fecha_hasta!='') {% and LEG.f_ingreso <= {Datetime(#SOURCE:@fecha_hasta)} %} {% %} %}
	 	{%?(#SOURCE:@where!='') {% and {%=#SOURCE:@where %} %} {% %} %}
	GROUP BY
		PER.oi_personal
')/ROWS/ROW

					for $r in sql('
			SELECT
				PER.oi_personal
			FROM 
				PER01_PERSONAL as PER, 
				PER02_PERSONAL_EMP as LEG, 
				ORG03_EMPRESAS as EMP,
				NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
				{%?(#SOURCE:@estructura!='') {% , ORG02_ESTRUC_PERS as ESTR %} {% %} %}
				{%?(#SOURCE:@ubicacion_desde!='' OR #SOURCE:@ubicacion_hasta!='') {% , ORG03_UBICACIONES as UBI %} {% %} %}
				{%?(#SOURCE:@convenio!='' OR #SOURCE:@categoria!='') {% , ORG18_CATEGORIAS AS CAT %} {% %} %}
				{%?(#SOURCE:@contrato!='') {% , PER28_CONTRATOS AS CON %} {% %} %}
			JOIN                                                   
				PER.oi_personal INNER LEG.oi_personal,
				LEG.oi_empresa INNER EMP.oi_empresa,
				LEG.oi_personal_emp LEFT OUTER SEC.id
				{%?(#SOURCE:@estructura!='') {% , ESTR.oi_personal_emp INNER LEG.oi_personal_emp %} {% %} %}
				{%?(#SOURCE:@ubicacion_desde!='' OR #SOURCE:@ubicacion_hasta!='') {% , UBI.oi_ubicacion INNER LEG.oi_ubicacion %} {% %} %}			
				{%?(#SOURCE:@convenio!='' OR #SOURCE:@categoria!='') {% , LEG.oi_categoria_ult INNER CAT.oi_categoria %} {% %} %}
				{%?(#SOURCE:@contrato!='') {% , LEG.oi_contrato LEFT OUTER CON.oi_contrato %} {% %} %}
			WHERE 1=1 
				{%?(#SOURCE:@activos='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
				{%?(#SOURCE:@empresa!='') {% and LEG.oi_empresa = {#SOURCE:@empresa} %} {% %} %}
      	{%?(#SOURCE:@centro_costo!='') {% and LEG.oi_ctro_costo_ult = {#SOURCE:@centro_costo} %} {% %} %}
				{%?(#SOURCE:@convenio!='') {% and CAT.oi_convenio = {#SOURCE:@convenio} %} {% %} %}
				{%?(#SOURCE:@categoria!='') {% and LEG.oi_categoria_ult = {#SOURCE:@categoria} %} {% %} %}
				{%?(#SOURCE:@contrato!='') {% and LEG.oi_contrato = {#SOURCE:@contrato} %} {% %} %}
				{%?(#SOURCE:@ubicacion_desde!='') 
					{% 
						and UBI.c_ubicacion >= {#FILTRO:@cubi_desde}
					%} {% %} %}
				{%?(#SOURCE:@ubicacion_hasta!='') 
					{% 
						and UBI.c_ubicacion <= {#FILTRO:@cubi_hasta}
					%} {% %} %}
				{%?(#ROWS:@estrs!='') {% and ESTR.oi_estructura in ({%=#ROWS:@estrs%}) %} {% %} %}
				{%?(#SOURCE:@soloconvenio='1') {% and LEG.oi_categoria_ult not in (select org18_categorias.oi_categoria from org18_categorias, org18_convenios join  org18_categorias.oi_convenio INNER org18_convenios.oi_convenio WHERE org18_convenios.c_convenio = \'00\')%} {% %} %}
				{%?(#SOURCE:@where!='') {% and {%=#SOURCE:@where %} %} {% %} %}
			GROUP BY
				PER.oi_personal
		')/ROWS/ROW
